import React, { useState, useRef, useEffect } from 'react';
import { colorFor, initials, isOnline, REPLY_BANKS } from '../data';
import styles from './ChatPanel.module.css';

export default function ChatPanel({ currentUser, contact, messages, onSendMessage, isTyping }) {
  const [text, setText] = useState('');
  const bottomRef = useRef(null);
  const inputRef = useRef(null);
  const EMOJIS = ['😊', '😂', '❤️', '👍', '🔥', '✅', '🎉', '😎', '🤔', '💡', '🙏', '👏'];
  const emojiIdx = useRef(0);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  useEffect(() => {
    inputRef.current?.focus();
  }, [contact]);

  function send() {
    const trimmed = text.trim();
    if (!trimmed) return;
    onSendMessage(trimmed);
    setText('');
    if (inputRef.current) inputRef.current.style.height = 'auto';
  }

  function handleKey(e) {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); }
  }

  function autoResize(e) {
    e.target.style.height = 'auto';
    e.target.style.height = Math.min(e.target.scrollHeight, 100) + 'px';
  }

  function insertEmoji() {
    setText(t => t + EMOJIS[emojiIdx.current++ % EMOJIS.length]);
    inputRef.current?.focus();
  }

  // Group messages by date
  const groups = [];
  let lastDate = '';
  messages.forEach(m => {
    const d = m.time.toDateString();
    if (d !== lastDate) { groups.push({ type: 'date', label: d === new Date().toDateString() ? 'Today' : m.time.toLocaleDateString([], { weekday: 'long', month: 'long', day: 'numeric' }) }); lastDate = d; }
    groups.push({ type: 'msg', msg: m });
  });

  const online = isOnline(contact.id);
  const cc = colorFor(contact.name);

  return (
    <div className={styles.panel}>
      {/* Header */}
      <div className={styles.header}>
        <div className={styles.headerAvatar} style={{ background: cc.bg, color: cc.text }}>
          {initials(contact.name)}
        </div>
        <div className={styles.headerInfo}>
          <strong>{contact.name}</strong>
          <span style={{ color: online ? 'var(--green)' : 'var(--text2)' }}>
            {online ? 'Online · Active now' : 'Offline'}
          </span>
        </div>
        <div className={styles.headerActions}>
          <div className={styles.iconBtn} title="Search">🔍</div>
          <div className={styles.iconBtn} title="Options">⋯</div>
        </div>
      </div>

      {/* Messages */}
      <div className={styles.messages}>
        {groups.map((g, i) => {
          if (g.type === 'date') return (
            <div key={`d${i}`} className={styles.dateDivider}>
              <span>{g.label}</span>
            </div>
          );
          const m = g.msg;
          const mine = m.from === currentUser.id;
          const sender = mine ? currentUser : contact;
          const sc = colorFor(sender.name);
          const nextMsg = groups[i + 1];
          const nextSame = nextMsg && nextMsg.type === 'msg' && nextMsg.msg.from === m.from;

          return (
            <div key={m.id} className={`${styles.row} ${mine ? styles.mine : ''}`}>
              {!mine && (
                <div className={styles.msgAvatar} style={{ background: sc.bg, color: sc.text }}>
                  {!nextSame ? initials(sender.name) : ''}
                </div>
              )}
              <div>
                <div className={mine ? styles.bubbleMine : styles.bubble}
                  dangerouslySetInnerHTML={{ __html: escHtml(m.text) }} />
                {!nextSame && (
                  <div className={styles.time}>
                    {m.time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    {mine && <span className={styles.readTick}> ✓✓</span>}
                  </div>
                )}
              </div>
            </div>
          );
        })}

        {isTyping && (
          <div className={styles.row}>
            <div className={styles.msgAvatar} style={{ background: cc.bg, color: cc.text }}>
              {initials(contact.name)}
            </div>
            <div className={styles.typingBubble}>
              <span className={styles.dot} />
              <span className={styles.dot} />
              <span className={styles.dot} />
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div className={styles.inputArea}>
        <div className={styles.inputWrap}>
          <button className={styles.emojiBtn} onClick={insertEmoji}>😊</button>
          <textarea
            ref={inputRef}
            className={styles.input}
            placeholder="Type a message…"
            rows={1}
            value={text}
            onChange={e => { setText(e.target.value); autoResize(e); }}
            onKeyDown={handleKey}
          />
        </div>
        <button className={styles.sendBtn} onClick={send}>
          <svg viewBox="0 0 24 24" width="16" height="16" fill="white">
            <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
          </svg>
        </button>
      </div>
    </div>
  );
}

function escHtml(t) {
  return t
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\n/g, '<br>');
}
